import app.cash.turbine.test
import dev.mokkery.answering.returns
import dev.mokkery.every
import dev.mokkery.mock
import kotlinx.coroutines.flow.flowOf
import kotlinx.coroutines.test.runTest
import ru.samtakoy.stocks.core.stocks.domain.model.Sector
import ru.samtakoy.stocks.core.stocks.domain.repository.SectorRepository
import kotlin.test.Test
import kotlin.test.assertEquals

class GetSectorsUseCaseTest {

    @Test
    fun invoke_repositoryEmitsList_forwardsList() = runTest {
        val sectors = listOf(
            Sector(id = 1, title = "Tech"),
            Sector(id = 2, title = "Energy"),
        )
        val repo = mock<SectorRepository> {
            every { getSectors() } returns flowOf(sectors)
        }
        val useCase = GetSectorsUseCase(repo)

        useCase().test {
            assertEquals(sectors, awaitItem())
            awaitComplete()
        }
    }

    @Test
    fun invoke_repositoryEmitsEmpty_forwardsEmpty() = runTest {
        val repo = mock<SectorRepository> {
            every { getSectors() } returns flowOf(emptyList())
        }
        val useCase = GetSectorsUseCase(repo)

        useCase().test {
            assertEquals(emptyList<Sector>(), awaitItem())
            awaitComplete()
        }
    }
}
"}
